// pages/student/MyApplications.jsx
import React, { useState } from 'react';
import { internships } from '../../data/mockData';
import './MyApplications.css';

const APPLICATIONS = [
  {
    ...internships[0],
    status: 'In Review',
    appliedDate: '2 days ago',
    statusHistory: [
      { step: 'Applied', done: true, date: 'May 9' },
      { step: 'Screening', done: true, date: 'May 10' },
      { step: 'In Review', done: true, date: 'May 11' },
      { step: 'Interview', done: false, date: null },
      { step: 'Offer', done: false, date: null },
    ],
    note: 'Your profile has been viewed by the hiring team.',
  },
  {
    ...internships[2],
    status: 'Applied',
    appliedDate: '1 week ago',
    statusHistory: [
      { step: 'Applied', done: true, date: 'May 4' },
      { step: 'Screening', done: false, date: null },
      { step: 'In Review', done: false, date: null },
      { step: 'Interview', done: false, date: null },
      { step: 'Offer', done: false, date: null },
    ],
    note: null,
  },
  {
    ...internships[1],
    status: 'Interview Scheduled',
    appliedDate: '2 weeks ago',
    statusHistory: [
      { step: 'Applied', done: true, date: 'Apr 28' },
      { step: 'Screening', done: true, date: 'Apr 30' },
      { step: 'In Review', done: true, date: 'May 2' },
      { step: 'Interview', done: true, date: 'May 14' },
      { step: 'Offer', done: false, date: null },
    ],
    note: 'Interview scheduled for May 14, 3:00 PM via Google Meet.',
  },
  {
    ...internships[4],
    status: 'Rejected',
    appliedDate: '3 weeks ago',
    statusHistory: [
      { step: 'Applied', done: true, date: 'Apr 22' },
      { step: 'Screening', done: true, date: 'Apr 24' },
      { step: 'In Review', done: false, date: null },
      { step: 'Interview', done: false, date: null },
      { step: 'Offer', done: false, date: null },
    ],
    note: 'Thank you for your interest. The position has been filled.',
  },
];

const STATUS_CONFIG = {
  'Applied':              { color: 'lavender', icon: '📋', cls: 'status-applied' },
  'In Review':            { color: 'amber',    icon: '🔍', cls: 'status-review' },
  'Interview Scheduled':  { color: 'cyan',     icon: '📅', cls: 'status-interview' },
  'Rejected':             { color: 'peach',    icon: '✕',  cls: 'status-rejected' },
  'Offer':                { color: 'mint',     icon: '🎉', cls: 'status-offer' },
};

function StatusTracker({ history }) {
  return (
    <div className="app-tracker">
      {history.map((step, i) => (
        <div key={step.step} className="app-tracker__step">
          <div className={`app-tracker__dot ${step.done ? 'app-tracker__dot--done' : ''}`}>
            {step.done ? '✓' : i + 1}
          </div>
          {i < history.length - 1 && (
            <div className={`app-tracker__line ${step.done && history[i+1].done ? 'app-tracker__line--done' : ''}`} />
          )}
          <div className="app-tracker__label">
            <span className="app-tracker__step-name">{step.step}</span>
            {step.date && <span className="app-tracker__date">{step.date}</span>}
          </div>
        </div>
      ))}
    </div>
  );
}

export default function MyApplications() {
  const [expanded, setExpanded] = useState(null);
  const [filter, setFilter] = useState('All');

  const statuses = ['All', ...Object.keys(STATUS_CONFIG)];
  const filtered = filter === 'All' ? APPLICATIONS : APPLICATIONS.filter(a => a.status === filter);

  return (
    <div className="myapps page-enter">
      <div className="myapps__header">
        <div>
          <h1 className="dashboard-title" style={{ marginBottom: 4 }}>My Applications</h1>
          <p style={{ color: 'var(--text-secondary)', fontSize: '0.88rem' }}>
            {APPLICATIONS.length} total applications · {APPLICATIONS.filter(a => a.status === 'In Review' || a.status === 'Interview Scheduled').length} active
          </p>
        </div>
        <div className="myapps__filters">
          {statuses.map(s => (
            <button
              key={s}
              className={`filter-chip ${filter === s ? 'filter-chip--active' : ''}`}
              onClick={() => setFilter(s)}>
              {s}
            </button>
          ))}
        </div>
      </div>

      {/* Summary row */}
      <div className="myapps__summary">
        {[
          { label: 'Total Applied', value: APPLICATIONS.length, color: 'lavender' },
          { label: 'In Review',     value: APPLICATIONS.filter(a => a.status === 'In Review').length, color: 'amber' },
          { label: 'Interviews',    value: APPLICATIONS.filter(a => a.status === 'Interview Scheduled').length, color: 'cyan' },
          { label: 'Offers',        value: APPLICATIONS.filter(a => a.status === 'Offer').length, color: 'mint' },
        ].map(s => (
          <div key={s.label} className={`myapps__sum-card myapps__sum-card--${s.color}`}>
            <span className="myapps__sum-val">{s.value}</span>
            <span className="myapps__sum-label">{s.label}</span>
          </div>
        ))}
      </div>

      {/* Application cards */}
      <div className="myapps__list">
        {filtered.map(app => {
          const cfg = STATUS_CONFIG[app.status] || STATUS_CONFIG['Applied'];
          const isOpen = expanded === app.id;
          return (
            <div key={app.id} className={`myapps__card ${isOpen ? 'myapps__card--open' : ''}`}>
              {/* Main row */}
              <div className="myapps__card-main" onClick={() => setExpanded(isOpen ? null : app.id)}>
                <div className="myapps__card-logo" style={{ color: app.logoColor }}>
                  {app.logo}
                </div>
                <div className="myapps__card-info">
                  <h4 className="myapps__card-role">{app.role}</h4>
                  <p className="myapps__card-meta">
                    {app.company} · {app.remote ? 'Remote' : app.location} · ₹{app.stipend.toLocaleString()}/mo
                  </p>
                </div>
                <div className="myapps__card-right">
                  <span className={`status-badge ${cfg.cls}`}>
                    {cfg.icon} {app.status}
                  </span>
                  <span className="myapps__card-date">Applied {app.appliedDate}</span>
                </div>
                <span className="myapps__expand-icon">{isOpen ? '▲' : '▼'}</span>
              </div>

              {/* Expanded detail */}
              {isOpen && (
                <div className="myapps__card-detail">
                  <div className="myapps__detail-divider" />
                  <StatusTracker history={app.statusHistory} />
                  {app.note && (
                    <div className="myapps__note">
                      <span className="myapps__note-icon">💬</span>
                      <p>{app.note}</p>
                    </div>
                  )}
                  <div className="myapps__detail-actions">
                    <button className="btn btn-ghost btn-sm">View Listing</button>
                    {app.status !== 'Rejected' && (
                      <button className="btn btn-secondary btn-sm">Withdraw</button>
                    )}
                  </div>
                </div>
              )}
            </div>
          );
        })}

        {filtered.length === 0 && (
          <div className="myapps__empty">
            <span style={{ fontSize: '2.5rem' }}>📭</span>
            <h3>No applications here</h3>
            <p>Try a different filter or start applying to internships.</p>
          </div>
        )}
      </div>
    </div>
  );
}
